import{_ as a,c as i,o as n,ag as s}from"./chunks/framework.Ct1Yelh8.js";const h=JSON.parse('{"title":"Why use Tailwind Buddy and key features","description":"","frontmatter":{"title":"Why use Tailwind Buddy and key features"},"headers":[],"relativePath":"about/index.md","filePath":"about/index.md"}'),t={name:"about/index.md"};function l(o,e,r,d,p,u){return n(),i("div",null,e[0]||(e[0]=[s('<h1 id="tailwind-buddy-your-friendly-helper-for-composing-tailwind-classes-🎨" tabindex="-1">Tailwind Buddy: Your Friendly Helper for Composing Tailwind Classes 🎨 <a class="header-anchor" href="#tailwind-buddy-your-friendly-helper-for-composing-tailwind-classes-🎨" aria-label="Permalink to &quot;Tailwind Buddy: Your Friendly Helper for Composing Tailwind Classes 🎨&quot;">​</a></h1><h2 id="what-problem-does-tailwind-buddy-solve" tabindex="-1">What problem does Tailwind Buddy solve? <a class="header-anchor" href="#what-problem-does-tailwind-buddy-solve" aria-label="Permalink to &quot;What problem does Tailwind Buddy solve?&quot;">​</a></h2><p>Tailwind Buddy addresses common challenges in managing Tailwind classes for complex, responsive designs. It offers a streamlined approach to:</p><ul><li>Organize and compose Tailwind classes for different component variants</li><li>Handle responsive designs with ease, reducing potential screen flickering in SSR applications</li><li>Manage compound variants that work responsively and can use custom prop values</li><li>Utilize a slot-based system for breaking down components into smaller, manageable parts</li><li>Works well with nativewind</li></ul><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li>Tools for building Tailwind variant components</li><li>Support for responsive variant props</li><li>Framework-agnostic solutions (works well with frameworks other than React)</li><li>SSR-friendly class generation, both responsive and non-responsive</li><li>React Native + Nativewind friendly. It integrates really well with this stack.</li><li>Ability to use slots for component composition</li><li>Compound variants that work responsively, overriding classes based on variant values and other props</li><li>High-performance variant utility. 5 times faster than tailwind variants and almost 2 times faster than CVA</li></ul><p>This library is inspired by <a href="https://cva.style/docs" target="_blank" rel="noreferrer">CVA</a> and <a href="https://github.com/nextui-org/tailwind-variants" target="_blank" rel="noreferrer">tailwind-variants</a>, offering our unique approach to solving common Tailwind challenges.</p>',7)]))}const m=a(t,[["render",l]]);export{h as __pageData,m as default};
